The Medici Bank is credited with developing the double-entry bookkeeping system. Here’s a simplified example in Python to illustrate how it works:

python
class Ledger:
    def __init__(self):
        self.transactions = []

    def record_debit(self, account, amount):
        self.transactions.append((account, 'Debit', amount))

    def record_credit(self, account, amount):
        self.transactions.append((account, 'Credit', amount))

    def get_balance(self, account):
        debits = sum(amount for acc, typ, amount in self.transactions 
                   if acc == account and typ == 'Debit')
        credits = sum(amount for acc, typ, amount in self.transactions 
                    if acc == account and typ == 'Credit')
        return debits - credits

# Example usage
ledger = Ledger()
ledger.record_debit('Cash', 1000)
ledger.record_credit('Revenue', 1000)
print(ledger.get_balance('Cash'))  # Output: 1000
